#include <iostream>

struct Point { long long x; long long y; };
Point operator+(const Point& left, const Point& right) { return {left.x + right.x, left.y + right.y}; }

int main() {
    Point left{}, right{};
    if (!(std::cin >> left.x >> left.y >> right.x >> right.y)) return 1;
    Point result = left + right;
    std::cout << result.x << ' ' << result.y << '\n';
}
